class Solution:
    def minimumValueSum(self, nums, andValues) -> int:
        from functools import lru_cache
        n, m = len(nums), len(andValues)
        INF = float('inf')
        @lru_cache(maxsize=None)
        def dp(i, j, cur_and):
            # place nums[i:] into segments j..m-1, current segment AND so far is cur_and
            if j == m:
                return 0 if i == n else INF
            if i == n:
                return INF
            new_and = cur_and & nums[i]
            res = INF
            # extend current segment
            if new_and >= andValues[j]:  # still possible to reach target
                ext = dp(i + 1, j, new_and)
                if ext < INF:
                    res = min(res, ext)
            # close segment here if AND matches
            if new_and == andValues[j]:
                close = dp(i + 1, j + 1, (1 << 20) - 1)
                if close < INF:
                    res = min(res, nums[i] + close)
            return res
        result = dp(0, 0, (1 << 20) - 1)
        return -1 if result == INF else result

