class Solution:
    def minimumValueSum(self, nums, andValues) -> int:
        from functools import lru_cache
        n, m = len(nums), len(andValues)
        INF = float('inf')
        FULL = (1 << 17) - 1  # all bits, bigger than max value 10^5
        @lru_cache(maxsize=None)
        def dp(i, j, cur_and):
            if j == m:
                return 0 if i == n else INF
            if i == n:
                return INF
            new_and = cur_and & nums[i]
            target = andValues[j]
            if new_and < target:
                return INF  # AND can never increase
            res = dp(i + 1, j, new_and)  # extend segment
            if new_and == target:  # close segment
                nxt = dp(i + 1, j + 1, FULL)
                if nxt < INF:
                    res = min(res, nums[i] + nxt)
            return res
        result = dp(0, 0, FULL)
        return -1 if result == INF else result

