var minimumValueSum = function(nums, andValues) {
    const n = nums.length, m = andValues.length;
    const FULL = (1 << 17) - 1;
    const INF = Infinity;
    const memo = new Map();
    function dp(i, j, curAnd) {
        if (j === m) return i === n ? 0 : INF;
        if (i === n) return INF;
        const key = `${i},${j},${curAnd}`;
        if (memo.has(key)) return memo.get(key);
        const newAnd = curAnd & nums[i];
        const target = andValues[j];
        if (newAnd < target) { memo.set(key, INF); return INF; }
        let res = dp(i + 1, j, newAnd);
        if (newAnd === target) {
            const nxt = dp(i + 1, j + 1, FULL);
            if (nxt < INF) res = Math.min(res, nums[i] + nxt);
        }
        memo.set(key, res);
        return res;
    }
    const result = dp(0, 0, FULL);
    return result === INF ? -1 : result;
};
